        try {
            const shopIds = assignedShops.map(s => s.id);
            await api.put(`/users/${selectedEmployee.id}/shops`, { shopIds });
            setShowAssignmentModal(false);
            // Refresh profile
            openProfile(selectedEmployee);
        } catch (err) {
            alert('Failed to update shop assignments');
        }
    };

    const toggleShopSelection = (shop) => {
        if (assignedShops.find(s => s.id === shop.id)) {
            setAssignedShops(assignedShops.filter(s => s.id !== shop.id));
        } else {
            setAssignedShops([...assignedShops, shop]);
        }
    };

    const handleDelete = async (id) => {
        if (!confirm('Are you sure? This will remove the user access.')) return;
        try {
            await api.delete(`/users/${id}`);
            fetchEmployees();
        } catch (err) {
            alert(err.response?.data || 'Failed to delete user');
            console.error(err);
        }
    };

    const handleCreateOrUpdate = async (e) => {
        e.preventDefault();
        try {
            if (editMode) {
                await api.put(`/users/${formData.id}`, formData);
            } else {
                await api.post('/users', formData);
            }
            setShowModal(false);
            resetForm();
            fetchEmployees();
        } catch (err) {
            alert(err.response?.data || 'Failed to save user');
        }
    };

    const resetForm = () => {
        setFormData({
            id: null,
            full_name: '',
            email: '',
            phone: '',
            password: '',
            role: 'salesman',
            permissions: SALESMAN_PERMISSIONS
        });
        setEditMode(false);
        setExpandedModule(null);
    };

    const openEditModal = (emp) => {
        setFormData({
            id: emp.id,
            full_name: emp.full_name,
            email: emp.email,
            phone: emp.phone || '',
            password: '',
            role: emp.role,
            permissions: emp.permissions || (emp.role === 'admin' ? ADMIN_PERMISSIONS : SALESMAN_PERMISSIONS)
        });
        setEditMode(true);
        setShowModal(true);
    };

    const openCreateModal = () => {
        resetForm();
        setShowModal(true);
    };

    const handleRoleChange = (role) => {
        let newPermissions = formData.permissions;
        if (role === 'admin') newPermissions = ADMIN_PERMISSIONS;
        else if (role === 'salesman') newPermissions = SALESMAN_PERMISSIONS;
        else if (role === 'custom' && !editMode) newPermissions = EMPTY_PERMISSIONS;

        setFormData({
            ...formData,
            role,
            permissions: newPermissions
        });
    };

    const togglePermission = (module, action) => {
        if (formData.role !== 'custom') return; // Only custom role can edit permissions

        setFormData({
            ...formData,
            permissions: {
                ...formData.permissions,
                [module]: {
                    ...formData.permissions[module],
                    [action]: !formData.permissions[module][action]
                }
            }
        });
    };

    if (user.role !== 'admin') return <div className="p-4 text-red-600 font-bold">Access Denied</div>;

    return (
        <div className="stock-page">
            <div className="page-header">
                <div>
                    <h1>Employee Management</h1>
                    <p className="subtitle">Choose between standard roles or create a custom access profile.</p>
                </div>
                <button className="btn btn-primary" onClick={openCreateModal}>
                    <Plus size={18} /> Add Employee
                </button>
            </div>

            <div className="table-container employees-list">
                <table className="stock-table">
                    <thead>
                        <tr>
                            <th>Name</th>
                            <th>Contact</th>
                            <th>Role Category</th>
                            <th>Joined</th>
                            <th>Actions</th>
                        </tr>
                    </thead>
                    <tbody>
                        {loading ? (
                            <tr>
                                <td colSpan="5" className="loading-cell">
                                    <div className="loading-container">
                                        <div className="spinner"></div>
                                        <span>Loading personnel database...</span>
                                    </div>
                                </td>
                            </tr>
                        ) : employees.length === 0 ? (
                            <tr><td colSpan="5" className="loading-cell">No employees found. Add one to get started.</td></tr>
                        ) : employees.map(emp => (
                            <tr key={emp.id} onClick={() => openProfile(emp)} className="clickable-row">
                                <td>
                                    <div className="user-cell">
                                        <div className="user-avatar">
                                            <User size={16} />
                                        </div>
                                        <span className="font-medium text-gray-900">
                                            {emp.full_name}
                                        </span>
                                    </div>
                                </td>
                                <td>
                                    <div className="flex flex-col gap-1">
                                        <div className="email-cell text-gray-500"><Mail size={14} /> {emp.email}</div>
                                        {emp.phone && <div className="email-cell text-gray-400"><Phone size={14} /> {emp.phone}</div>}
                                    </div>
                                </td>
                                <td>
                                    <div className="flex flex-col gap-1">
                                        <span className={`badge ${emp.role === 'admin' ? 'badge-green' : emp.role === 'custom' ? 'badge-gray' : 'badge-blue'}`}>
                                            {emp.role === 'admin' ? <ShieldCheck size={12} /> : emp.role === 'custom' ? <Settings2 size={12} /> : <Briefcase size={12} />}
                                            {emp.role.toUpperCase()}
                                        </span>
                                    </div>
                                </td>
                                <td className="text-gray-400 text-sm">{new Date(emp.created_at).toLocaleDateString()}</td>
                                <td className="actions-cell">
                                    <button className="icon-btn" onClick={(e) => { e.stopPropagation(); openEditModal(emp); }}>
                                        <Edit size={18} />
                                    </button>
                                    <button className="icon-btn delete-btn" onClick={(e) => { e.stopPropagation(); handleDelete(emp.id); }}>
                                        <Trash2 size={18} />
                                    </button>
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>

            {/* Simplified Role Modal */}
            {showModal && (
                <div className="modal-overlay">
                    <div className="modal-content permissions-modal-content">
                        <div className="modal-header">
                            <h2>{editMode ? `Edit Access: ${formData.full_name}` : 'Create New Personnel'}</h2>
                        </div>
                        <form onSubmit={handleCreateOrUpdate} className="personnel-form">
                            <div className="managed-form">
                                <div className="form-sections-grid">
                                    <div className="info-section">
                                        <h3 className="section-title">Identity & Role</h3>
                                        <div className="form-group">
                                            <label>Full Name</label>
                                            <input
                                                type="text"
                                                value={formData.full_name}
                                                onChange={e => setFormData({ ...formData, full_name: e.target.value })}
                                                required
                                                placeholder="Enter full name"
                                            />
                                        </div>
                                        <div className="form-group">
                                            <label>Email Address</label>
                                            <input
                                                type="email"
                                                value={formData.email}
                                                onChange={e => setFormData({ ...formData, email: e.target.value })}
                                                required
                                                placeholder="email@company.com"
                                            />
                                        </div>
                                        <div className="form-group">
                                            <label>Phone Number</label>
                                            <input
                                                type="tel"
                                                value={formData.phone}
                                                onChange={e => setFormData({ ...formData, phone: e.target.value })}
                                                placeholder="+91 9876543210"
                                            />
                                        </div>
                                        <div className="form-group">
                                            <label>Role</label>
                                            <select
                                                value={formData.role}
                                                onChange={e => handleRoleChange(e.target.value)}
                                            >
                                                <option value="salesman">Salesman</option>
                                                <option value="admin">Admin</option>
                                                <option value="custom">Custom</option>
                                            </select>
                                        </div>
                                        {!editMode && (
                                            <div className="form-group">
                                                <label>Access Password</label>
                                                <input
                                                    type="password"
                                                    value={formData.password}
                                                    onChange={e => setFormData({ ...formData, password: e.target.value })}
                                                    required
                                                    placeholder="Initialize password"
                                                />
                                            </div>
                                        )}
                                    </div>

                                    <div className="permissions-section">
                                        <h3 className="section-title">Access Configuration</h3>
                                        {formData.role !== 'custom' ? (
                                            <div className="role-preview-card">
                                                <p className="text-sm text-gray-500 mb-2">
                                                    {formData.role === 'admin'
                                                        ? 'Administrators have full access to all modules and settings.'
                                                        : 'Salesmen have standard access to stock, customers, and sales creation.'}
                                                </p>
                                                <div className="preview-badges">
                                                    {MODULES.filter(m => formData.permissions[m.id]?.view).map(m => (
                                                        <div key={m.id} className="preview-badge">
                                                            <Check size={10} color="#10b981" />
                                                            {m.name}
                                                        </div>
                                                    ))}
                                                </div>
                                            </div>
                                        ) : (
                                            <>
                                                <p className="section-desc">Choose which modules this custom user can access.</p>
                                                <div className="modules-permissions-list">
                                                    {MODULES.map(module => {
                                                        const isModuleOn = formData.permissions[module.id]?.view;
                                                        return (
                                                            <div key={module.id} className={`module-item ${!isModuleOn ? 'module-off' : ''}`}>
                                                                <div className="module-header-container">
                                                                    <div
                                                                        className={`module-header ${expandedModule === module.id ? 'active' : ''}`}
                                                                        onClick={() => setExpandedModule(expandedModule === module.id ? null : module.id)}
                                                                    >
                                                                        <div className="flex items-center gap-2">
                                                                            {expandedModule === module.id ? <ChevronDown size={14} /> : <ChevronRight size={14} />}
                                                                            <span className="font-medium">{module.name}</span>
                                                                        </div>
                                                                    </div>
                                                                    <div className="module-toggle-wrapper">
                                                                        <div
                                                                            className={`master-toggle ${isModuleOn ? 'on' : ''}`}
                                                                            onClick={() => togglePermission(module.id, 'view')}
                                                                        >
                                                                            <div className="toggle-dot"></div>
                                                                        </div>
                                                                    </div>
                                                                </div>

                                                                {expandedModule === module.id && (
                                                                    <div className={`module-actions-grid ${!isModuleOn ? 'disabled-grid' : ''}`}>
                                                                        {(() => {
                                                                            let subActions = ACTIONS.filter(a => a !== 'view');
                                                                            if (module.id === 'finance') subActions = FINANCE_ACTIONS;
                                                                            if (module.id === 'settings') subActions = SETTINGS_ACTIONS;

                                                                            if (subActions.length === 0) return <p className="text-xs text-gray-400 italic p-2">Full access granted by master toggle.</p>;

                                                                            return subActions.map(action => (
                                                                                <div
                                                                                    key={action}
                                                                                    className={`action-toggle ${formData.permissions[module.id]?.[action] ? 'checked' : ''} ${!isModuleOn ? 'disabled' : ''}`}
                                                                                    onClick={() => isModuleOn && togglePermission(module.id, action)}
                                                                                >
                                                                                    <div className="checkbox">
                                                                                        {formData.permissions[module.id]?.[action] && <Check size={12} />}
                                                                                    </div>
                                                                                    <span className="capitalize">{action.replace('_', ' ')}</span>
                                                                                </div>
                                                                            ));
                                                                        })()}
                                                                    </div>
                                                                )}
                                                            </div>
                                                        );
                                                    })}
                                                </div>
                                            </>
                                        )}
                                    </div>
                                </div>
                            </div>

                            <div className="modal-actions">
                                <button type="button" className="btn btn-secondary" onClick={() => setShowModal(false)}>Cancel</button>
                                <button type="submit" className="btn btn-primary">{editMode ? 'Update Employee' : 'Create Employee'}</button>
                            </div>
                        </form>
                    </div>
                </div>
            )}

            {/* Employee Profile Modal */}
            {showProfile && selectedEmployee && (
                <div className="modal-overlay">
                    <div className="modal-content permissions-modal-content">
                        <div className="modal-header flex justify-between items-center">
                            <h2>Employee Profile</h2>
                            <button className="icon-btn" onClick={() => setShowProfile(false)}><Plus size={24} style={{ transform: 'rotate(45deg)' }} /></button>
                        </div>
                        <div className="managed-form profile-view-content">
                            {profileLoading ? (
                                <div className="loading-container">
                                    <div className="spinner"></div>
                                    <span>Loading details...</span>
                                </div>
                            ) : (
                                <>
                                    <div className="profile-header-grid">
                                        <div className="profile-identity">
                                            <div className="profile-avatar">
                                                <User size={40} />
                                            </div>
                                            <div className="profile-main-info">
                                                <h3>{selectedEmployee.full_name}</h3>
                                                <p className="text-gray-500 flex items-center gap-2"><Mail size={14} /> {selectedEmployee.email}</p>
                                                {selectedEmployee.phone && <p className="text-gray-500 flex items-center gap-2"><Phone size={14} /> {selectedEmployee.phone}</p>}
                                                <span className={`badge mt-2 ${selectedEmployee.role === 'admin' ? 'badge-green' : 'badge-blue'}`}>
                                                    {selectedEmployee.role.toUpperCase()}
                                                </span>
                                            </div>
                                        </div>
                                        <div className="profile-work-info">
                                            <div className="info-stat">
                                                <span className="info-label">Joined On</span>
                                                <span className="info-val">{new Date(selectedEmployee.created_at).toLocaleDateString()}</span>
                                            </div>
                                            <div className="info-stat">
                                                <span className="info-label">Account Status</span>
                                                <span className="info-val text-green-600 font-bold">Active</span>
                                            </div>
                                        </div>
                                    </div>

                                    <h3 className="section-title"><Briefcase size={16} /> Sales Performance</h3>
                                    {performance ? (
                                        <div className="performance-stats-grid">
                                            <div className="p-stat-card">
                                                <span className="p-stat-label">Total Revenue</span>
                                                <span className="p-stat-value">Γé╣{Number(performance.total_revenue || 0).toLocaleString()}</span>
                                            </div>
                                            <div className="p-stat-card">
                                                <span className="p-stat-label">Total Orders</span>
                                                <span className="p-stat-value">{performance.total_orders}</span>
                                            </div>
                                            <div className="p-stat-card">
                                                <span className="p-stat-label">Active Customers</span>
                                                <span className="p-stat-value">{performance.total_customers}</span>
                                            </div>
                                        </div>
                                    ) : (
                                        <p className="text-gray-400 italic">Calculating performance data...</p>
                                    )}

                                    <div className="section-header-row">
                                        <h3 className="section-title"><Check size={16} /> Assigned Shops ({assignedShops.length})</h3>
                                        <button className="btn btn-secondary btn-sm" onClick={() => setShowAssignmentModal(true)}>
                                            Manage Assignments
                                        </button>
                                    </div>
                                    <div className="assigned-shops-list">
                                        {assignedShops.length > 0 ? (
                                            assignedShops.map(shop => (
                                                <div key={shop.id} className="assigned-shop-item">
                                                    <div className="shop-info">
                                                        <span className="shop-name">{shop.name}</span>
                                                        <span className="shop-addr">{shop.address}</span>
                                                    </div>
                                                    <span className="shop-phone">{shop.phone}</span>
                                                </div>
                                            ))
                                        ) : (
                                            <div className="empty-shops-state">
                                                <Store size={32} />
                                                <span>No shops assigned to this employee yet.</span>
                                                <button className="btn btn-primary btn-sm mt-2" onClick={() => setShowAssignmentModal(true)}>
                                                    Assign Now
                                                </button>
                                            </div>
                                        )}
                                    </div>
                                </>
                            )}
                        </div>
                    </div>
                </div>
            )}

            {/* Shop Assignment Modal */}
            {showAssignmentModal && (
                <div className="modal-overlay assignment-overlay">
                    <div className="modal-content shop-select-modal">
                        <div className="modal-header">
                            <h2>Select Targeted Shops</h2>
                            <p className="text-xs text-gray-500">Pick the shops this salesman will manage.</p>
                        </div>
                        <div className="managed-form shop-selection-grid">
                            {allShops.map(shop => (
                                <div
                                    key={shop.id}
                                    className={`shop-option-item ${assignedShops.find(s => s.id === shop.id) ? 'selected' : ''}`}
                                    onClick={() => toggleShopSelection(shop)}
                                >
                                    <div className="selection-indicator">
                                        {assignedShops.find(s => s.id === shop.id) && <Check size={14} />}
                                    </div>
                                    <div className="shop-option-details">
                                        <span className="opt-name">{shop.name}</span>
                                        <span className="opt-customer text-xs text-gray-400">{shop.customer_name}</span>
                                    </div>
                                </div>
                            ))}
                        </div>
                        <div className="modal-actions">
                            <button className="btn btn-secondary" onClick={() => setShowAssignmentModal(false)}>Cancel</button>
                            <button className="btn btn-primary" onClick={handleUpdateShopAssignments}>Update Assignments</button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default Employees;

import React, { useEffect, useState } from 'react';
import api from '../services/api';
import {
    Search,
    CreditCard,
    ArrowDownLeft,
    Clock,
    CheckCircle,
    AlertCircle,
    User,
    History,
    IndianRupee,
    Plus,
    X,
    TrendingUp,
    FileText,
    StickyNote
} from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import './Finance.css';

const Finance = ({ user }) => {
    const navigate = useNavigate();
    const [dues, setDues] = useState([]);
    const [history, setHistory] = useState([]);
    const [orders, setOrders] = useState([]);
    const [loading, setLoading] = useState(true);
    const [search, setSearch] = useState('');
    const [activeTab, setActiveTab] = useState('dues');

    // Payment Modal State (General Dues)
    const [showPaymentModal, setShowPaymentModal] = useState(false);
    const [selectedCustomer, setSelectedCustomer] = useState(null);
    const [paymentData, setPaymentData] = useState({
        amount: '',
        notes: ''
    });

    // Credit Note Modal State (Order Specific)
    const [paymentModal, setPaymentModal] = useState(false);
    const [selectedOrder, setSelectedOrder] = useState(null);
    const [paymentAmount, setPaymentAmount] = useState('');

    useEffect(() => {
        fetchAllData();
    }, []);

    const fetchAllData = async () => {
        setLoading(true);
        try {
            // Added timestamp to prevent caching
            const timestamp = Date.now();
            const [custRes, saleRes] = await Promise.all([
                api.get(`/customers?t=${timestamp}`),
                api.get(`/sales?t=${timestamp}`)
            ]);

            // For Dues Tab - Total Outstanding calculation
            const allCustomers = custRes.data;
            const sortedDues = allCustomers
                .filter(c => Number(c.balance) > 0.01) // Filter tiny dust balances
                .sort((a, b) => Number(b.balance) - Number(a.balance));

            setDues(sortedDues);

            // For History Tab
            const paymentsOnly = saleRes.data.filter(t => t.type === 'payment');
            setHistory(paymentsOnly);

            // For Credit Note Tab
            const orderList = saleRes.data.filter(t => t.type === 'order');
            setOrders(orderList);

        } catch (err) {
            console.error('Finance sync error:', err);
        } finally {
            setLoading(false);
        }
    };

    const handleRecordPayment = async (e) => {
        e.preventDefault();
        try {
            await api.post('/sales', {
                customer_id: selectedCustomer.id,
                type: 'payment',
                amount: parseFloat(paymentData.amount),
                notes: paymentData.notes
            });
            setShowPaymentModal(false);
            setPaymentData({ amount: '', notes: '' });
            setSelectedCustomer(null);
            fetchAllData();
            alert('Payment recorded successfully!');
        } catch (err) {
            alert('Failed to record payment');
        }
    };

    const handleUpdateOrderPayment = async (e) => {
        e.preventDefault();
        if (!paymentAmount || isNaN(paymentAmount)) return;

        try {
            await api.put(`/sales/payment/${selectedOrder.id}`, {
                amountPaid: parseFloat(paymentAmount)
            });
            setPaymentModal(false);
            setPaymentAmount('');
            setSelectedOrder(null);
            fetchAllData();
            alert('Order payment updated successfully');
        } catch (err) {
            alert('Failed to update payment');
        }
    };

    const getStatusStyles = (status) => {
        switch (status) {
            case 'Payment Completed':
                return { bg: '#dcfce7', color: '#10b981', icon: <CheckCircle size={14} /> };
            case 'Partially Paid':
                return { bg: '#fef9c3', color: '#a16207', icon: <TrendingUp size={14} /> };
            default:
                return { bg: '#f1f5f9', color: '#64748b', icon: <Clock size={14} /> };
        }
    };

    const canSeeTab = (tabId) => {
        if (user.role === 'admin') return true;
        return user.permissions?.finance?.[tabId] === true;
    };

    useEffect(() => {
        if (user.role !== 'admin') {
            const perms = user.permissions?.finance;
            if (perms) {
                if (perms.dues && activeTab === 'dues') return;
                if (perms.credit && activeTab === 'credit') return;
                if (perms.history && activeTab === 'history') return;

                // If currently active tab is not allowed, switch to first allowed
                if (perms.dues) setActiveTab('dues');
                else if (perms.credit) setActiveTab('credit');
                else if (perms.history) setActiveTab('history');
            }
        }
    }, [user, activeTab]);

    const totalOutstanding = dues.reduce((sum, c) => sum + Number(c.balance), 0);

    // Calculate Today's Collection
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    const todayCollection = history
        .filter(h => {
            const hDate = new Date(h.transaction_date);
            hDate.setHours(0, 0, 0, 0);
            return hDate.getTime() === today.getTime();
        })
        .reduce((sum, h) => sum + Number(h.total_amount), 0);

    const filteredDues = dues.filter(c =>
        c.full_name.toLowerCase().includes(search.toLowerCase())
    );

    const filteredHistory = history.filter(h =>
        h.customer_name.toLowerCase().includes(search.toLowerCase()) ||
        h.shop_name?.toLowerCase().includes(search.toLowerCase())
    );

    const filteredOrders = orders.filter(o =>
        o.customer_name.toLowerCase().includes(search.toLowerCase()) ||
        o.shop_name?.toLowerCase().includes(search.toLowerCase()) ||
        o.id.includes(search)
    );

    if (loading) return <div className="loading-state">Synchronizing financial records...</div>;

    return (
        <div className="finance-page">
            <header className="page-header">
                <div>
                    <h1>Finance Hub</h1>
                    <p className="subtitle">Unified management of dues, payments, and credit notes.</p>
                </div>
            </header>

            <div className="finance-stats">
                <div className="stat-card outstanding">
                    <div className="stat-icon"><IndianRupee size={24} /></div>
                    <div className="stat-content">
                        <label>Total Outstanding</label>
                        <h3 className="text-red-500">Γé╣{totalOutstanding.toLocaleString('en-IN', { minimumFractionDigits: 2 })}</h3>
                    </div>
                </div>
                <div className="stat-card collection">
                    <div className="stat-icon"><TrendingUp size={24} /></div>
                    <div className="stat-content">
                        <label>Collection Today</label>
                        <h3 className="text-emerald-500">Γé╣{todayCollection.toLocaleString('en-IN', { minimumFractionDigits: 2 })}</h3>
                    </div>
                </div>
            </div>

            <div className="finance-container">
                <div className="finance-tabs">
                    {canSeeTab('dues') && (
                        <button
                            className={`tab ${activeTab === 'dues' ? 'active' : ''}`}
                            onClick={() => setActiveTab('dues')}
                        >
                            <AlertCircle size={18} /> Bill Dues
                        </button>
                    )}
                    {canSeeTab('credit') && (
                        <button
                            className={`tab ${activeTab === 'credit' ? 'active' : ''}`}
                            onClick={() => setActiveTab('credit')}
                        >
                            <StickyNote size={18} /> Credit Notes
                        </button>
                    )}
                    {canSeeTab('history') && (
                        <button
                            className={`tab ${activeTab === 'history' ? 'active' : ''}`}
                            onClick={() => setActiveTab('history')}
                        >
                            <History size={18} /> Payment History
                        </button>
                    )}

                    <div className="tab-search">
                        <Search size={16} />
                        <input
                            type="text"
                            placeholder="Search..."
                            value={search}
                            onChange={(e) => setSearch(e.target.value)}
                        />
                    </div>
                </div>

                <div className="tab-content">
                    {activeTab === 'dues' && (
                        <div className="table-container">
                            <table className="finance-table">
                                <thead>
                                    <tr>
                                        <th>CUSTOMER</th>
                                        <th>CONTACT DETAILS</th>
                                        <th>REASON</th>
                                        <th className="text-right">DUE AMOUNT</th>
                                        <th className="text-center">ACTION</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    {filteredDues.length === 0 ? (
                                        <tr><td colSpan="5" className="empty-cell">No outstanding bills found.</td></tr>
                                    ) : filteredDues.map(c => (
                                        <tr key={c.id}>
                                            <td className="customer-cell">
                                                <div className="avatar">{c.full_name[0]}</div>
                                                <div className="info">
                                                    <span className="name">{c.full_name}</span>
                                                    <span className="id">CUST-{c.id.slice(0, 5).toUpperCase()}</span>
                                                </div>
                                            </td>
                                            <td>
                                                <div className="contact-info">
                                                    <span>{c.phone}</span>
                                                    <span className="email">{c.email}</span>
                                                </div>
                                            </td>
                                            <td><div className="badge badge-date"><Clock size={12} /> Pending Collection</div></td>
                                            <td className="text-right font-bold text-red-600">
                                                Γé╣{Number(c.balance).toLocaleString('en-IN', { minimumFractionDigits: 2 })}
                                            </td>
                                            <td className="text-center">
                                                <button
                                                    className="btn-pay"
                                                    onClick={() => {
                                                        setSelectedCustomer(c);
                                                        setShowPaymentModal(true);
                                                    }}
                                                >
                                                    <CreditCard size={14} /> Record Payment
                                                </button>
                                            </td>
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    )}

                    {activeTab === 'credit' && (
                        <div className="table-container">
                            <table className="finance-table credit-table">
                                <thead>
                                    <tr>
                                        <th>ORDER ID</th>
                                        <th>SHOP / CUSTOMER</th>
                                        <th>TOTAL</th>
                                        <th>PAID</th>
                                        <th>DUE</th>
                                        <th>STATUS</th>
                                        <th className="text-center">ACTION</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    {filteredOrders.length === 0 ? (
                                        <tr><td colSpan="7" className="empty-cell">No credit notes found.</td></tr>
                                    ) : filteredOrders.map(order => {
                                        const styles = getStatusStyles(order.status);
                                        const balance = Number(order.total_amount) - Number(order.paid_amount);
                                        return (
                                            <tr key={order.id}>
                                                <td className="id-cell">ORD-{order.id.slice(0, 8).toUpperCase()}</td>
                                                <td>
                                                    <div className="info">
                                                        <span className="name">{order.shop_name}</span>
                                                        <span className="shop">{order.customer_name}</span>
                                                    </div>
                                                </td>
                                                <td className="font-bold">Γé╣{Number(order.total_amount).toLocaleString('en-IN')}</td>
                                                <td className="text-emerald-600 font-bold">Γé╣{Number(order.paid_amount).toLocaleString('en-IN')}</td>
                                                <td className="text-red-600 font-black">Γé╣{balance.toLocaleString('en-IN')}</td>
                                                <td>
                                                    <span className="status-chip" style={{ backgroundColor: styles.bg, color: styles.color }}>
                                                        {styles.icon} {order.status}
                                                    </span>
                                                </td>
                                                <td className="text-center">
                                                    <div className="flex gap-2 justify-center">
                                                        <button className="btn-pay-sm" onClick={() => { setSelectedOrder(order); setPaymentModal(true); }}>
                                                            <CreditCard size={14} /> Pay
                                                        </button>
                                                        <button className="icon-btn-sm" onClick={() => navigate(`/dashboard/invoice/${order.id}`)}>
                                                            <FileText size={14} />
                                                        </button>
                                                    </div>
                                                </td>
                                            </tr>
                                        );
                                    })}
                                </tbody>
                            </table>
                        </div>
                    )}

                    {activeTab === 'history' && (
                        <div className="table-container">
                            <table className="finance-table">
                                <thead>
                                    <tr>
                                        <th>DATE</th>
                                        <th>CUSTOMER / SHOP</th>
                                        <th>STATUS</th>
                                        <th>NOTES</th>
                                        <th className="text-right">COLLECTED</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    {filteredHistory.length === 0 ? (
                                        <tr><td colSpan="5" className="empty-cell">No payment history found.</td></tr>
                                    ) : filteredHistory.map(h => (
                                        <tr key={h.id}>
                                            <td className="date-cell">
                                                <span>{new Date(h.transaction_date).toLocaleDateString('en-GB').replace(/\//g, '.')}</span>
                                                <span className="time">{new Date(h.transaction_date).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
                                            </td>
                                            <td>
                                                <div className="info">
                                                    <span className="name">{h.shop_name || 'Direct Collection'}</span>
                                                    <span className="shop">{h.customer_name}</span>
                                                </div>
                                            </td>
                                            <td><div className="badge badge-success"><CheckCircle size={12} /> Received</div></td>
                                            <td className="notes-cell">{h.notes || '-'}</td>
                                            <td className="text-right font-black text-emerald-600">
                                                +Γé╣{Number(h.total_amount).toLocaleString('en-IN', { minimumFractionDigits: 2 })}
                                            </td>
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    )}
                </div>
            </div>

            {/* General Payment Modal */}
            {showPaymentModal && (
                <div className="modal-overlay">
                    <div className="modal-content finance-modal">
                        <div className="modal-header">
                            <h2><Plus size={20} /> Record New Payment</h2>
                            <button className="close-btn" onClick={() => setShowPaymentModal(false)}><X size={20} /></button>
                        </div>
                        <form onSubmit={handleRecordPayment}>
                            <div className="selected-customer-box">
                                <User size={16} />
                                <span>Paying Ref: <strong>{selectedCustomer?.full_name}</strong></span>
                                <span className="balance-badge">Due: Γé╣{Number(selectedCustomer?.balance).toFixed(2)}</span>
                            </div>

                            <div className="form-group">
                                <label>Collection Amount (Γé╣)</label>
                                <div className="amount-input">
                                    <IndianRupee size={18} />
                                    <input
                                        type="number"
                                        step="0.01"
                                        placeholder="0.00"
                                        value={paymentData.amount}
                                        onChange={e => setPaymentData({ ...paymentData, amount: e.target.value })}
                                        required
                                        autoFocus
                                    />
                                </div>
                            </div>

                            <div className="form-group">
                                <label>Payment Reference / Notes</label>
                                <textarea
                                    placeholder="e.g. Cash, GPay, Bank Transfer Reference..."
                                    value={paymentData.notes}
                                    onChange={e => setPaymentData({ ...paymentData, notes: e.target.value })}
                                    rows="3"
                                ></textarea>
                            </div>

                            <div className="modal-actions">
                                <button type="button" className="btn-secondary" onClick={() => setShowPaymentModal(false)}>Cancel</button>
                                <button type="submit" className="btn-primary">Confirm Collection</button>
                            </div>
                        </form>
                    </div>
                </div>
            )}

            {/* Credit Note Specific Modal */}
            {paymentModal && (
                <div className="modal-overlay">
                    <div className="modal-content credit-modal">
                        <div className="modal-header">
                            <h2>Record Payment Entry</h2>
                            <button className="close-btn" onClick={() => setPaymentModal(false)}><X size={20} /></button>
                        </div>
                        <form onSubmit={handleUpdateOrderPayment}>
                            <div className="order-context">
                                <div className="context-item">
                                    <label>ORDER TOTAL</label>
                                    <span>Γé╣{Number(selectedOrder?.total_amount).toLocaleString('en-IN')}</span>
                                </div>
                                <div className="context-item highlight">
                                    <label>REMAINING DUE</label>
                                    <span>Γé╣{(Number(selectedOrder?.total_amount) - Number(selectedOrder?.paid_amount)).toLocaleString('en-IN')}</span>
                                </div>
                            </div>

                            <div className="amount-input-box">
                                <IndianRupee size={24} color="#10b981" />
                                <input
                                    type="number"
                                    placeholder="0"
                                    value={paymentAmount}
                                    onChange={(e) => setPaymentAmount(e.target.value)}
                                    max={Number(selectedOrder?.total_amount) - Number(selectedOrder?.paid_amount)}
                                    required
                                    autoFocus
                                />
                            </div>

                            <div className="quick-actions">
                                <button
                                    type="button"
                                    className="btn-link"
                                    onClick={() => setPaymentAmount((Number(selectedOrder?.total_amount) - Number(selectedOrder?.paid_amount)).toString())}
                                >
                                    Settling Full Payment?
                                </button>
                            </div>

                            <div className="modal-actions">
                                <button type="button" className="btn-secondary" onClick={() => setPaymentModal(false)}>Cancel</button>
                                <button type="submit" className="btn-primary">Update Account</button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
};

export default Finance;

import React, { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import api from '../services/api';
import { Printer, ArrowLeft, Download, Mail, Building2, Store, User, FileText } from 'lucide-react';
import LoadingSpinner from '../components/LoadingSpinner';
import './Invoice.css';

const Invoice = () => {
    const { id } = useParams();
    const navigate = useNavigate();
    const [sale, setSale] = useState(null);
    const [items, setItems] = useState([]);
    const [payments, setPayments] = useState([]);
    const [company, setCompany] = useState({ company_name: 'Secuvra Stock Manager', company_address: 'Enterprise Plaza, Tech Hub' });
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        fetchData();
        fetchCompanySettings();
    }, [id]);

    const fetchData = async () => {
        try {
            const [saleRes, itemsRes, paymentsRes] = await Promise.all([
                api.get(`/sales/${id}`),
                api.get(`/sales/items/${id}`),
                api.get(`/sales/payments/${id}`)
            ]);
            setSale(saleRes.data);
            setItems(itemsRes.data);
            setPayments(paymentsRes.data);
        } catch (err) {
            console.error(err);
        } finally {
            setLoading(false);
        }
    };

    const fetchCompanySettings = async () => {
        try {
            const res = await api.get('/settings');
            if (res.data && res.data.company_name) {
                setCompany(res.data);
            }
        } catch (err) {
            console.error(err);
        }
    };

    const handlePrint = () => {
        window.print();
    };

    if (loading) return <LoadingSpinner fullScreen message="Generating Invoice..." />;
    if (!sale) return <div className="error-container">Invoice not found.</div>;

    const subtotal = items.reduce((sum, item) => sum + (item.quantity * item.price), 0);

    return (
        <div className="invoice-page-container">
            <div className="invoice-actions no-print">
                <button onClick={() => navigate(-1)} className="btn-action">
                    <ArrowLeft size={18} /> Back
                </button>
                <div className="flex gap-2">
                    <button onClick={handlePrint} className="btn-action btn-primary">
                        <Printer size={18} /> Print Invoice
                    </button>
                </div>
            </div>

            <div className="invoice-paper" id="invoice-content">
                <header className="invoice-header">
                    <div className="company-info">
                        <div className="company-logo">
                            <Building2 size={32} color="#10b981" />
                            <span>{company.company_name}</span>
                        </div>
                        <p className="company-address">{company.company_address}</p>
                    </div>
                    <div className="invoice-meta">
                        <h1>INVOICE</h1>
                        <div className="meta-row">
                            <span className="label">INVOICE ID</span>
                            <span className="value">: &nbsp;ORD-{sale.id.slice(0, 8).toUpperCase()}</span>
                        </div>
                        <div className="meta-row">
                            <span className="label">DATE</span>
                            <span className="value">: &nbsp;{new Date(sale.transaction_date).toLocaleDateString('en-GB').replace(/\//g, '.')}</span>
                        </div>

                    </div>
                </header>

                <div className="invoice-billing">
                    <div className="billing-box">
                        <div className="section-title">TO:</div>
                        <h3 style={{ fontSize: '1.25rem', marginBottom: '0.25rem' }}>{sale.shop_name}</h3>
                        <p style={{ fontWeight: 700, color: '#10b981', marginBottom: '0.5rem', fontSize: '1rem' }}>{sale.customer_name}</p>
                        <p>{sale.shop_address}</p>
                        <p>Phone: {sale.shop_phone}</p>
                    </div>
                </div>

                <div className="invoice-table-container">
                    <table className="invoice-table">
                        <thead>
                            <tr>
                                <th>#</th>
                                <th>Item Description</th>
                                <th className="text-right">Qty</th>
                                <th className="text-right">Unit Price</th>
                                <th className="text-right">Total Amount</th>
                            </tr>
                        </thead>
                        <tbody>
                            {items.map((item, index) => (
                                <tr key={index}>
                                    <td>{index + 1}</td>
                                    <td className="font-bold">{item.name}</td>
                                    <td className="text-right">{item.quantity}</td>
                                    <td className="text-right">Γé╣{parseFloat(item.price).toLocaleString('en-IN', { minimumFractionDigits: 2 })}</td>
                                    <td className="text-right font-bold">Γé╣{(item.quantity * item.price).toLocaleString('en-IN', { minimumFractionDigits: 2 })}</td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>

                <div className="invoice-summary">
                    <div className="notes-section">
                        <h4>Notes & Instructions</h4>
                        <p>{sale.notes || 'No additional notes provided for this transaction.'}</p>
                    </div>
                    <div className="totals-section">
                        <div className="total-row">
                            <span>Order Total</span>
                            <span>Γé╣{parseFloat(sale.total_amount).toLocaleString('en-IN', { minimumFractionDigits: 2 })}</span>
                        </div>
                        {(() => {
                            const balance = parseFloat(sale.total_amount) - parseFloat(sale.paid_amount || 0);
                            const isOverpaid = balance < 0;
                            return (
                                <>
                                    <div className="total-row">
                                        <span>{isOverpaid ? 'Amount Received' : 'Amount Paid'}</span>
                                        <span className="text-emerald-600">Γé╣{parseFloat(sale.paid_amount || 0).toLocaleString('en-IN', { minimumFractionDigits: 2 })}</span>
                                    </div>
                                    {isOverpaid ? (
                                        <div className="total-row">
                                            <span>Change Returned</span>
                                            <span style={{ color: '#f59e0b', fontWeight: 'bold' }}>Γé╣{Math.abs(balance).toLocaleString('en-IN', { minimumFractionDigits: 2 })}</span>
                                        </div>
                                    ) : balance > 0 ? (
                                        <div className="total-row grand-total">
                                            <span>Balance Due</span>
                                            <span className="text-red-600">Γé╣{balance.toLocaleString('en-IN', { minimumFractionDigits: 2 })}</span>
                                        </div>
                                    ) : null}
                                </>
                            );
                        })()}
                    </div>
                </div>

                <div className="invoice-payments">
                    <h4>Payment History</h4>
                    <table className="invoice-table">
                        <thead>
                            <tr>
                                <th>Date</th>
                                <th>Description</th>
                                <th className="text-right">Amount</th>
                            </tr>
                        </thead>
                        <tbody>
                            {payments.length === 0 && (
                                <tr>
                                    <td colSpan="3" style={{ textAlign: 'center', fontStyle: 'italic', padding: '1rem' }}>No separate payment records. Initial payment is included in totals.</td>
                                </tr>
                            )}
                            {payments.map((p, i) => (
                                <tr key={i}>
                                    <td>{new Date(p.transaction_date).toLocaleDateString()}</td>
                                    <td>{p.notes}</td>
                                    <td className="text-right">Γé╣{parseFloat(p.total_amount).toLocaleString('en-IN', { minimumFractionDigits: 2 })}</td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>

                <footer className="invoice-footer">
                    <p className="disclaimer">This is a computer-generated invoice and does not require a physical signature.</p>
                    <div className="footer-bottom">
                        <p>Thank you for your business!</p>
                        <p>Salesman: {sale.salesman_name}</p>
                    </div>
                </footer>
            </div>
        </div>
    );
};

export default Invoice;

import React, { useEffect, useState } from 'react';
import api from '../services/api';
import { Plus, Search, Trash2, Edit, X, ShoppingCart, Store, User, Hash, Package, ClipboardCheck, FileText, ChevronDown, Filter, Loader2, Navigation } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import LoadingSpinner from '../components/LoadingSpinner';
import './StockList.css';

const SalesList = ({ user }) => {
    const navigate = useNavigate();
    const [sales, setSales] = useState([]);
    const [loading, setLoading] = useState(true);
    const [statusFilter, setStatusFilter] = useState('All');
    const [updatingId, setUpdatingId] = useState(null);

    useEffect(() => {
        fetchSales();
    }, []);

    const fetchSales = async () => {
        try {
            const res = await api.get('/sales');
            setSales(res.data);
            setLoading(false);
        } catch (err) {
            console.error(err);
            setLoading(false);
        }
    };

    const handleDelete = async (id) => {
        if (!window.confirm('Are you sure you want to delete this order?')) return;
        try {
            await api.delete(`/sales/${id}`);
            fetchSales();
        } catch (err) {
            alert('Failed to delete order');
        }
    };

    const handleGetDirections = (location) => {
        if (!location) return;
        if (location.startsWith('http://') || location.startsWith('https://')) {
            window.open(location, '_blank');
        } else {
            const url = `https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(location)}`;
            window.open(url, '_blank');
        }
    };

    const handleStatusUpdate = async (id, nextStatus, currentStatus) => {
        // Prevent update if already updating or if status hasn't changed
        if (updatingId === id || nextStatus === currentStatus) return;

        setUpdatingId(id);
        try {
            await api.put(`/sales/${id}`, { status: nextStatus });
            // Auto-refresh the list after successful update
            await fetchSales();
        } catch (err) {
            alert('Failed to update status');
        } finally {
            setUpdatingId(null);
        }
    };

    const filteredSales = sales.filter(sale => {
        if (statusFilter === 'All') return true;
        return sale.status === statusFilter;
    });

    const getPaymentStatus = (sale) => {
        const total = Number(sale.total_amount);
        const paid = Number(sale.paid_amount || 0);
        if (paid >= total) return 'Fully Paid';
        if (paid > 0) return 'Partially Paid';
        return 'Unpaid';
    };

    const getPaymentColor = (status) => {
        if (status === 'Fully Paid') return 'badge-emerald';
        if (status === 'Partially Paid') return 'badge-blue'; // Using blue/orange as preferred
        return 'badge-gray'; // Unpaid
    };

    return (
        <>
            {loading && <LoadingSpinner fullScreen message="Loading orders..." />}
            <div className="stock-page">
                <div className="page-header">
                    <div>
                        <h1>Sales & Orders</h1>
                        <p className="subtitle">
                            {user.role === 'admin' ? 'Viewing all salesman orders' : 'Viewing your orders'}
                        </p>
                    </div>
                    <div style={{ display: 'flex', gap: '12px', alignItems: 'center' }}>
                        <div style={{ position: 'relative' }}>
                            <select
                                className="btn"
                                value={statusFilter}
                                onChange={(e) => setStatusFilter(e.target.value)}
                                style={{
                                    backgroundColor: 'white',
                                    border: '1px solid #d1d5db',
                                    color: '#374151',
                                    paddingLeft: '12px',
                                    paddingRight: '36px',
                                    paddingTop: '10px',
                                    paddingBottom: '10px',
                                    borderRadius: '6px',
                                    appearance: 'none',
                                    cursor: 'pointer',
                                    fontSize: '0.875rem',
                                    fontWeight: '500'
                                }}
                            >
                                <option value="All">All Status</option>
                                <option value="Ordered">Ordered</option>
                                <option value="Dispatched">Dispatched</option>
                                <option value="Delivered">Delivered</option>
                            </select>
                            <Filter size={16} style={{ position: 'absolute', right: '10px', top: '50%', transform: 'translateY(-50%)', color: '#9ca3af', pointerEvents: 'none' }} />
                        </div>
                        <button className="btn btn-primary" onClick={() => navigate('/dashboard/create-order')}>
                            <Plus size={18} /> New Order
                        </button>
                    </div>
                </div>

                <div className="table-container">
                    <table className="stock-table">
                        <thead>
                            <tr>
                                <th>Date</th>
                                <th>Shop</th>
                                <th>Customer</th>
                                <th>Salesman</th>
                                <th>Payment</th>
                                <th>Order Status</th>
                                <th>Amount</th>
                                <th>Actions</th>
                            </tr>
                        </thead>
                        <tbody>
                            {!loading && filteredSales.length === 0 ? (
                                <tr><td colSpan="8" className="loading-cell">No orders found.</td></tr>
                            ) : filteredSales.map(sale => {
                                const paymentStatus = getPaymentStatus(sale);
                                return (
                                    <tr key={sale.id}>
                                        <td className="date-cell">
                                            <div className="flex flex-col">
                                                <span className="font-bold text-gray-700">{new Date(sale.transaction_date).toLocaleDateString()}</span>
                                                <span className="text-[10px] text-gray-400 font-bold uppercase">{new Date(sale.transaction_date).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
                                            </div>
                                        </td>
                                        <td>
                                            <div className="flex items-center gap-2">
                                                <div className="p-2 bg-emerald-50 rounded-lg text-emerald-600">
                                                    <Store size={16} />
                                                </div>
                                                <span className="font-bold text-gray-800">{sale.shop_name || 'Direct Sale'}</span>
                                            </div>
                                        </td>
                                        <td>
                                            <span className="badge badge-blue">
                                                <User size={12} className="inline mr-1" />
                                                {sale.customer_name}
                                            </span>
                                        </td>
                                        <td>
                                            <span className="badge badge-purple">
                                                {sale.salesman_name}
                                            </span>
                                        </td>
                                        <td>
                                            <span className={`badge ${getPaymentColor(paymentStatus)}`}>
                                                {paymentStatus}
                                            </span>
                                        </td>
                                        <td>
                                            <div
                                                className={`badge ${sale.status === 'Delivered' ? 'badge-emerald' : sale.status === 'Dispatched' ? 'badge-blue' : 'badge-gray'}`}
                                                style={{
                                                    position: 'relative',
                                                    display: 'inline-flex',
                                                    alignItems: 'center',
                                                    paddingRight: '1.75rem',
                                                    cursor: updatingId === sale.id ? 'wait' : 'pointer',
                                                    minWidth: '110px',
                                                    opacity: updatingId === sale.id ? 0.7 : 1,
                                                    pointerEvents: updatingId === sale.id ? 'none' : 'auto'
                                                }}
                                            >
                                                <span className="uppercase font-bold" style={{ flex: 1 }}>{sale.status}</span>
                                                {updatingId === sale.id ? (
                                                    <Loader2
                                                        size={14}
                                                        className="absolute right-2 top-1/2 transform -translate-y-1/2"
                                                        style={{ animation: 'spin 1s linear infinite' }}
                                                    />
                                                ) : (
                                                    <ChevronDown size={14} className="absolute right-2 top-1/2 transform -translate-y-1/2 opacity-60" />
                                                )}
                                                <select
                                                    value={sale.status}
                                                    onChange={(e) => handleStatusUpdate(sale.id, e.target.value, sale.status)}
                                                    disabled={updatingId === sale.id}
