                                                    <Edit size={18} />
                                                </button>
                                                <button className="icon-btn delete-btn" title="Delete Order" onClick={() => handleDelete(sale.id)}>
                                                    <Trash2 size={18} />
                                                </button>
                                            </div>
                                        </td>
                                    </tr>
                                );
                            })}
                        </tbody>
                    </table>
                </div>
            </div>
        </>
    );
};

