import React, { useState, useEffect } from 'react';
import api from '../services/api';
import { User, Lock, Save, AlertCircle, CheckCircle } from 'lucide-react';
import './StockList.css'; // Inheriting basic layout
import './Settings.css'; // New Styles

const Settings = ({ user }) => {
    const [formData, setFormData] = useState({
        full_name: '',
        email: '',
        current_password: '', // Kept for logic if needed later
        new_password: '',
        confirm_password: ''
    });
    const [msg, setMsg] = useState({ type: '', text: '' });
    const [companyData, setCompanyData] = useState({ company_name: '', company_address: '' });

    useEffect(() => {
        if (user) {
            setFormData(prev => ({ ...prev, full_name: user.full_name || '', email: user.email || '' }));
            if (user.role === 'admin') fetchCompanySettings();
        }
    }, [user]);

    const fetchCompanySettings = async () => {
        try {
            const res = await api.get('/settings');
            if (res.data) setCompanyData(res.data);
        } catch (err) {
            console.error(err);
        }
    };

    const handleChange = (e) => {
        setFormData({ ...formData, [e.target.name]: e.target.value });
    };

    const handleCompanyChange = (e) => {
        setCompanyData({ ...companyData, [e.target.name]: e.target.value });
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        setMsg({ type: '', text: '' });

        if (formData.new_password && formData.new_password !== formData.confirm_password) {
            setMsg({ type: 'error', text: 'New passwords do not match' });
            return;
        }

        try {
            const payload = { full_name: formData.full_name };
            if (formData.new_password) payload.password = formData.new_password;

            const res = await api.put('/auth/profile', payload);

            if (user.role === 'admin') {
                await api.put('/settings', companyData);
                window.dispatchEvent(new Event('company-settings-updated'));
            }

            setMsg({ type: 'success', text: 'Settings updated successfully!' });

            // Update local storage user info
            const storedUser = JSON.parse(localStorage.getItem('user'));
            const updatedUser = { ...storedUser, ...res.data };
            localStorage.setItem('user', JSON.stringify(updatedUser));

            // Optional: reset password fields
            setFormData(prev => ({ ...prev, current_password: '', new_password: '', confirm_password: '' }));

            // Auto hide success msg
            setTimeout(() => setMsg({ type: '', text: '' }), 3000);
        } catch (err) {
            console.error(err);
            setMsg({ type: 'error', text: 'Failed to update profile.' });
        }
    };

    return (
        <div className="stock-page">
            <div className="page-header">
                <div>
                    <h1>Account Settings</h1>
                    <p className="subtitle">Update your profile and security preferences.</p>
                </div>
            </div>

            <div className="settings-container">
                {msg.text && (
                    <div className={`alert ${msg.type === 'error' ? 'alert-error' : 'alert-success'}`}>
                        {msg.type === 'error' ? <AlertCircle size={20} /> : <CheckCircle size={20} />}
                        {msg.text}
                    </div>
                )}

                <form onSubmit={handleSubmit}>
                    {user && user.role === 'admin' && (
                        <>
                            <div className="settings-group">
                                <div className="settings-group-title">
                                    <User size={20} color="#10b981" /> Company Information
                                </div>
                                <div className="form-input-container">
                                    <label>Company Name</label>
                                    <input
                                        type="text"
                                        name="company_name"
                                        value={companyData.company_name}
                                        onChange={handleCompanyChange}
                                        placeholder="Enter company name"
                                    />
                                </div>
                                <div className="form-input-container">
                                    <label>Company Address</label>
                                    <input
                                        type="text"
                                        name="company_address"
                                        value={companyData.company_address}
                                        onChange={handleCompanyChange}
                                        placeholder="Enter company address"
                                    />
                                </div>
                            </div>
                            <div className="separator"></div>
                        </>
                    )}

                    <div className="settings-group">
                        <div className="settings-group-title">
                            <User size={20} color="#10b981" /> Personal Information
                        </div>

                        <div className="form-input-container">
                            <label>Full Name</label>
                            <input
                                type="text"
                                name="full_name"
                                value={formData.full_name}
                                onChange={handleChange}
                                required
                            />
                        </div>
                        <div className="form-input-container">
                            <label>Email Address</label>
                            <input
                                type="email"
                                name="email"
                                value={formData.email}
                                disabled
                            />
                            <p className="form-hint">Email address cannot be changed.</p>
                        </div>
                    </div>

                    <div className="separator"></div>

                    <div className="settings-group">
                        <div className="settings-group-title">
                            <Lock size={20} color="#10b981" /> Security
                        </div>
                        <div className="form-input-container">
                            <label>New Password</label>
                            <input
                                type="password"
                                name="new_password"
                                value={formData.new_password}
                                onChange={handleChange}
                                placeholder="Leave blank to keep current"
                            />
                        </div>
                        <div className="form-input-container">
                            <label>Confirm New Password</label>
                            <input
                                type="password"
                                name="confirm_password"
                                value={formData.confirm_password}
                                onChange={handleChange}
                                placeholder="Confirm new password"
                            />
                        </div>
                    </div>

                    <div className="action-row">
                        <button type="submit" className="btn-save">
                            <Save size={18} /> Save Changes
                        </button>
                    </div>
                </form>
            </div>
        </div>
    );
};

export default Settings;

import React, { useEffect, useState } from "react";
import api from "../services/api";
import {
  Plus,
  Search,
  Trash2,
  Edit,
  Store,
  User,
  Phone,
  MapPin,
  Navigation,
  Map,
  ArrowLeft,
  X,
} from "lucide-react";
import LoadingSpinner from "../components/LoadingSpinner";
import "./StockList.css"; // Reusing common table/page styles
import "./Shops.css";

const Shops = () => {
  const [shops, setShops] = useState([]);
  const [customers, setCustomers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState("");
  const [user, setUser] = useState(null);
  const [employees, setEmployees] = useState([]);
  const [areas, setAreas] = useState([]);
  const [selectedArea, setSelectedArea] = useState(null);

  const [showAreaModal, setShowAreaModal] = useState(false);
  const [newAreaName, setNewAreaName] = useState("");
  const [editingAreaId, setEditingAreaId] = useState(null);
  const [editAreaName, setEditAreaName] = useState('');

  const [showModal, setShowModal] = useState(false);
  const [showHistory, setShowHistory] = useState(false);
  const [selectedShop, setSelectedShop] = useState(null);
  const [historyTab, setHistoryTab] = useState("orders");
  const [allTransactions, setAllTransactions] = useState([]);
  const [historyLoading, setHistoryLoading] = useState(false);

  const [formData, setFormData] = useState({
    id: null,
    name: "",
    address: "",
    phone: "",
    email: "",
    customer_id: "",
    salesman_id: "",
    location: "",
    area_id: "",
  });

  useEffect(() => {
    const storedUser = JSON.parse(localStorage.getItem("user"));
    if (storedUser) {
      setUser(storedUser);
      if (storedUser.role === "admin") {
        fetchEmployees();
      }
    }
    fetchAreas();
    fetchShops();
    fetchCustomers();
  }, []);

  const fetchAreas = async () => {
    try {
      const response = await api.get("/areas");
      setAreas(response.data);
    } catch (error) {
      console.error("Error fetching areas:", error);
    }
  };

  const fetchShops = async () => {
    try {
      const response = await api.get("/shops");
      setShops(response.data);
      setLoading(false);
    } catch (error) {
      console.error("Error fetching shops:", error);
      setLoading(false);
    }
  };

  const fetchCustomers = async () => {
    try {
      const res = await api.get("/customers");
      setCustomers(res.data);
    } catch (error) {
      console.error("Error fetching customers:", error);
    }
  };

  const fetchEmployees = async () => {
    try {
      const res = await api.get("/users");
      setEmployees(res.data);
    } catch (error) {
      console.error("Error fetching employees:", error);
    }
  };

  const hasPermission = (module, action) => {
    if (!user) return false;
    if (user.role === "admin") return true;
    const permissions = user.permissions || {};
    return permissions[module]?.[action] === true;
  };

  const openHistory = async (shop) => {
    try {
      setSelectedShop(shop);
      setHistoryLoading(true);
      const res = await api.get("/sales"); // This will be filtered by salesman if applicable
      const shopSales = res.data.filter((t) => t.shop_id === shop.id);
      setAllTransactions(shopSales);
      setShowHistory(true);
      setHistoryTab("orders");
    } catch (err) {
      console.error(err);
      alert("Failed to load shop history");
    } finally {
      setHistoryLoading(false);
    }
  };

  const handleCreateOrUpdateShop = async (e) => {
    e.preventDefault();

    // Phone validation: should be exactly 10 digits
    const phoneDigits = formData.phone.replace(/[^0-9]/g, "");
    if (phoneDigits.length !== 10) {
      alert("Please enter a valid 10-digit phone number");
      return;
    }

    const finalData = {
      ...formData,
      phone: `+91 ${phoneDigits}`,
    };

    try {
      if (formData.id) {
        await api.put(`/shops/${formData.id}`, finalData);
      } else {
        await api.post("/shops", finalData);
      }
      setShowModal(false);
      resetForm();
      fetchShops();
    } catch (error) {
      alert("Failed to save shop");
    }
  };

  const resetForm = () => {
    setFormData({
      id: null,
      name: "",
      address: "",
      phone: "",
      email: "",
      customer_id: "",
      salesman_id: "",
      location: "",
      area_id: selectedArea ? selectedArea.id : "",
    });
  };

  const handleCreateArea = async (e) => {
    e.preventDefault();
    if (!newAreaName.trim()) return;
    try {
      await api.post('/areas', { name: newAreaName.trim() });
      setNewAreaName('');
      fetchAreas();
    } catch (err) {
      alert('Failed to save Area. It might already exist.');
    }
  };

  const handleUpdateArea = async (areaId) => {
    if (!editAreaName.trim()) return;
    try {
      await api.put(`/areas/${areaId}`, { name: editAreaName.trim() });
      setEditingAreaId(null);
      fetchAreas();
      fetchShops();
    } catch (err) {
      alert('Failed to update Area. Name might exist.');
    }
  };

  const handleDeleteArea = async (areaId, areaName) => {
    if (!window.confirm(`Are you sure you want to delete the Area "${areaName}"? Shops in this area will lose their area assignment.`)) return;
    try {
      await api.delete(`/areas/${areaId}`);
      fetchAreas();
      fetchShops();
      if (selectedArea && selectedArea.id === areaId) setSelectedArea(null);
    } catch (err) {
      alert('Failed to delete Area.');
    }
  };

  const openEditShop = (shop) => {
    // Strip prefix for editing
    const rawPhone = shop.phone ? shop.phone.replace("+91 ", "") : "";
    setFormData({
      id: shop.id,
      name: shop.name,
      address: shop.address,
      phone: rawPhone,
      email: shop.email || "",
      customer_id: shop.customer_id,
      salesman_id: shop.salesman_id || "",
      location: shop.location || "",
      area_id: shop.area_id || "",
    });
    setShowModal(true);
  };

  const handleGetDirections = (location) => {
    if (!location) return;
    if (location.startsWith("http://") || location.startsWith("https://")) {
      window.open(location, "_blank");
    } else {
      const url = `https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(location)}`;
      window.open(url, "_blank");
    }
  };

  const handleDeleteShop = async (id) => {
    if (!window.confirm("Are you sure you want to delete this shop?")) return;
    try {
      await api.delete(`/shops/${id}`);
      fetchShops();
    } catch (error) {
      console.error(error);
    }
  };

  const filteredShops = shops.filter((shop) => {
    const matchesArea = selectedArea ? shop.area_id === selectedArea.id : true;
    const matchesSearch =
      shop.name.toLowerCase().includes(search.toLowerCase()) ||
      shop.phone.includes(search);
    return matchesArea && matchesSearch;
  });

  const getAreaShopCount = (areaId) => {
    return shops.filter((s) => s.area_id === areaId).length;
  };

  return (
    <div className="stock-page">
      <div className="page-header">
        <div style={{ display: "flex", alignItems: "center", gap: "1rem" }}>
          {selectedArea && (
            <button
              className="icon-btn"
              onClick={() => setSelectedArea(null)}
              style={{
                padding: "8px",
                backgroundColor: "white",
                border: "1px solid #d1d5db",
                borderRadius: "8px",
              }}
            >
              <ArrowLeft size={20} />
            </button>
          )}
          <div>
            <h1>
              {selectedArea
                ? `${selectedArea.name} - Shops`
                : "Shop Management"}
            </h1>
            <p className="subtitle">
              {selectedArea
                ? "Manage branches in this area."
                : "Select an area to view shops or manage branches."}
            </p>
          </div>
        </div>
        <div className="header-actions">
          {!selectedArea && hasPermission('shops', 'create') && (
            <button className="btn btn-secondary" onClick={() => setShowAreaModal(true)}>
              <Map size={18} /> Manage Areas
            </button>
          )}   {hasPermission("shops", "create") && (
            <button
              className="btn btn-primary"
              onClick={() => {
                resetForm();
                setShowModal(true);
              }}
            >
              <Plus size={18} /> Add Shop
            </button>
          )}
        </div>
      </div>

      <div className="controls-bar">
        <div className="search-box">
          <Search size={18} color="#9ca3af" />
          <input
            type="text"
            placeholder="Search by Shop Name or Phone..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
          />
        </div>
      </div>

      {!selectedArea ? (
        <div
          style={{
            display: "grid",
            gridTemplateColumns: "repeat(auto-fill, minmax(250px, 1fr))",
            gap: "16px",
            padding: "0 16px 16px",
          }}
        >
          {areas.map((area) => (
            <div
              key={area.id}
              onClick={() => setSelectedArea(area)}
              style={{
                backgroundColor: "white",
                padding: "20px",
                borderRadius: "12px",
                cursor: "pointer",
